import {
  Box,
  Typography,
  Card,
  CardContent,
  Button,
  Grid,
} from "@mui/material";

const projects = [
  { id: 1, name: "Project A" },
  { id: 2, name: "Project B" },
];

export default function ManagerDashboard() {
  return (
    <Box sx={{ p: 4 }}>
      {/* Title */}
      <Typography variant="h4" fontWeight="bold" mb={4}>
        Project Manager Dashboard 🚀
      </Typography>

      {/* Grid */}
      <Grid container spacing={4}>
        {projects.map((project) => (
          <Grid item xs={12} sm={6} md={4} key={project.id}>
            <Card
              sx={{
                borderRadius: 4,
                boxShadow: 4,
                transition: "0.3s",
                "&:hover": {
                  transform: "translateY(-5px)",
                  boxShadow: 8,
                },
              }}
            >
              <CardContent>
                {/* Project Name */}
                <Typography variant="h6" fontWeight="bold" mb={2}>
                  {project.name}
                </Typography>

                {/* Thumbnail Box */}
                <Box
                  sx={{
                    height: 150,
                    border: "2px dashed #ccc",
                    borderRadius: 2,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    mb: 2,
                    fontSize: 14,
                    color: "#777",
                  }}
                >
                  Preview Image / BIM Thumbnail
                </Box>

                {/* Button */}
                <Button
                  fullWidth
                  variant="contained"
                  sx={{
                    borderRadius: 3,
                    textTransform: "none",
                    fontWeight: "bold",
                  }}
                  onClick={() => alert(`Open ${project.name}`)}
                >
                  View Project
                </Button>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
}
